// Label every item from this Jira query with _type = 'updated'
// Aggregate reads this field — no guessing, no re-classification.
return $input.all().map(item => ({
  json: { ...item.json, _type: 'updated' }
}));

// Label every item from this Jira query with _type = 'created'
// Aggregate reads this field — no guessing, no re-classification.
return $input.all().map(item => ({
  json: { ...item.json, _type: 'created' }
}));

// Label every item from this Jira query with _type = 'completed'
// Aggregate reads this field — no guessing, no re-classification.
return $input.all().map(item => ({
  json: { ...item.json, _type: 'completed' }
}));

// Label every item from this Jira query with _type = 'dueSoon'
// Aggregate reads this field — no guessing, no re-classification.
return $input.all().map(item => ({
  json: { ...item.json, _type: 'dueSoon' }
}));

// Label every item from this Jira query with _type = 'epics'
// Aggregate reads this field — no guessing, no re-classification.
return $input.all().map(item => ({
  json: { ...item.json, _type: 'epics' }
}));

// Label every item from this Jira query with _type = 'allIssues'
// Aggregate reads this field — no guessing, no re-classification.
return $input.all().map(item => ({
  json: { ...item.json, _type: 'allIssues' }
}));

// Prepare Assignee KPI rows — reads purely from $input
const d = $input.first().json;
const rows = (d.kpis?.assigneeKPIs || []);
if (rows.length === 0) return [{ json: { skipped: true } }];
return rows.map(a => ({ json: {
    report_id:          d.id,
    project_key:        d.project_key,
    project_short:      d.project_short,
    sprint_name:        d.sprint_name,
    week_start:         d.week_start,
    assignee:           a.assignee,
    total_issues:       a.total          ?? 0,
    done:               a.done           ?? 0,
    in_progress:        a.inProgress     ?? 0,
    todo:               a.toDo           ?? 0,
    blocked:            a.blocked        ?? 0,
    story_points_done:  a.spDone         ?? 0,
    story_points_total: a.storyPoints    ?? 0,
    avg_lead_time:      a.avgLeadTime    ?? null,
    completion_rate:    a.completionRate ?? 0,
}}));

// Prepare Epic Snapshot rows — reads purely from $input
const d = $input.first().json;
const epics = d.epicProgress || [];
if (epics.length === 0) return [{ json: { skipped: true } }];
return epics.map(e => ({ json: {
    report_id:       d.id,
    project_key:     d.projectKey,
    sprint_name:     d.sprintName,
    week_start:      d.weekStart,
    epic_key:        e.key,
    epic_name:       e.name,
    total_issues:    e.total        ?? 0,
    done_pct:        e.donePct      ?? 0,
    in_progress_pct: e.inProgPct    ?? 0,
    todo_pct:        e.todoPct      ?? 0,
}}));

// ============================================================
// PROJECT CONFIG — change only this block per workflow instance
// Duplicate this workflow for each Jira project, update below.
// ============================================================

const PROJECT_KEY  = 'AIBAP';
const JIRA_BASE_URL = 'https://your-domain.atlassian.net';  // ← change to your Jira domain
const EMAIL_TO     = 'user@example.com';

// ── Date range (automatic) ───────────────────────────────────
const now          = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const sevenDaysAhead = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);

const fmtISO  = (d) => d.toISOString().split('T')[0];
const fmtLong = (d) => d.toLocaleDateString('en-GB', {
  day: 'numeric', month: 'long', year: 'numeric'
});

return [{
  json: {
    projectKey:    PROJECT_KEY,
    jiraBaseUrl:   JIRA_BASE_URL,
    emailTo:       EMAIL_TO,

    today:         fmtISO(now),
    sevenDaysAgo:  fmtISO(sevenDaysAgo),
    sevenDaysAhead:fmtISO(sevenDaysAhead),
    dateRange:     `${fmtLong(sevenDaysAgo)} — ${fmtLong(now)}`,
    weekLabel:     `Week of ${fmtLong(sevenDaysAgo)}`,
    weekStart:     fmtISO(sevenDaysAgo),
    weekEnd:       fmtISO(now),
  }
}];

// Stamp the config item with _type = 'config'
return $input.all().map(item => ({
  json: { ...item.json, _type: 'config' }
}));

// ============================================================
// BUILD EMAIL HTML — Slim digest v2 (business-reader restructure)
// Order: Header → Alert → Exec Summary → Health+Timeline →
//        3 Key Numbers → Donut Status → Blocked Detail → CTA → Footer
// ============================================================

const d = $input.first().json;
const {
  projectKey, projectName, projectShort,
  sprintName, sprintGoal, sprintDates, sprintStartFmt, sprintEndFmt,
  sprintPct, sprintDaysLeft,
  reportTitle, weekLabel, dateRange,
  metrics, kpis, statusOverview, dueSoonIssues
} = d;

const JIRA_BASE = $('CONFIGURATION NODE').first().json.jiraBaseUrl + "/browse";
const BRAND     = '#0F3D6E';
const BRAND_ACC = '#0052CC';
const SURFACE   = '#FFFFFF';
const SURFACE2  = '#F4F5F7';
const BORDER    = '#DFE1E6';
const TEXT1     = '#172B4D';
const TEXT2     = '#5E6C84';
const TEXT3     = '#8993A4';

const STATUS_COLOR_MAP = {
  'Done':'#36B37E','Terminé':'#36B37E',
  'In Progress':'#0052CC','En cours':'#0052CC',
  'In Review':'#6554C0','En révision':'#6554C0','Revue en cours':'#6554C0',
  'To Do':'#DFE1E6','À faire':'#DFE1E6','Nouveau':'#DFE1E6','New':'#DFE1E6',
  'Blocked':'#BF2600'
};

const normalizeStatus = (s) => {
  if (!s) return 'Unknown';
  const map = {
    'Done':'Done','Terminé':'Done',
    'In Progress':'In Progress','En cours':'In Progress',
    'In Review':'In Review','En révision':'In Review','Revue en cours':'In Review',
    'To Do':'To Do','À faire':'To Do','Nouveau':'To Do','New':'To Do',
    'Blocked':'Blocked',
  };
  if (map[s]) return map[s];
  const sl = s.toLowerCase();
  if (sl.startsWith('terminé') || sl.startsWith('termine')) return 'Done';
  if (sl.startsWith('en cours')) return 'In Progress';
  if (sl.includes('révision') || sl.includes('review')) return 'In Review';
  if (sl.startsWith('à faire') || sl === 'nouveau' || sl === 'new') return 'To Do';
  return s;
};

// ── Health colors ─────────────────────────────────────────────
const healthColor = {'On Track':'#006644','Slight Risk':'#FF8B00','At Risk':'#BF2600','Critical':'#BF2600'}[kpis.sprintHealth] || TEXT2;
const healthBg    = {'On Track':'#E3FCEF','Slight Risk':'#FFFAE6','At Risk':'#FFEBE6','Critical':'#FFEBE6'}[kpis.sprintHealth] || SURFACE2;
const healthBorder= {'On Track':'#36B37E','Slight Risk':'#FF8B00','At Risk':'#BF2600','Critical':'#BF2600'}[kpis.sprintHealth] || BORDER;

// ── Sprint timeline helpers ───────────────────────────────────
const daysLabel = sprintDaysLeft===0 ? 'Sprint ended'
  : sprintDaysLeft===1 ? '1 day left'
  : sprintDaysLeft!==null ? `${sprintDaysLeft} days left` : '';
const daysColor = sprintDaysLeft===0 ? '#BF2600' : (sprintPct>=80 ? '#FF8B00' : TEXT2);
const donePct = metrics.totalIssues > 0
  ? Math.round((statusOverview.find(s=>s.status==='Done'||s.status==='Terminé')?.count||0) / metrics.totalIssues * 100) : 0;
const barColor = (sprintPct>=90 && donePct<60) ? '#BF2600' : (sprintPct>=70 && donePct<40) ? '#FF8B00' : '#36B37E';
const sprintBandFill = Math.max(0, Math.min(100, sprintPct));

// ── Donut SVG ─────────────────────────────────────────────────
const totalIssues = metrics.totalIssues || 1;
const R_OUT=54, R_IN=34, CX=64, CY=64, GAP=0.04;
let angle = -Math.PI/2;
const donutPaths = statusOverview.map(s => {
  const frac = s.count/totalIssues;
  const sweep = frac*2*Math.PI - GAP;
  if (sweep<=0) return '';
  const sA=angle+GAP/2, eA=sA+sweep;
  angle += frac*2*Math.PI;
  const x1=CX+R_OUT*Math.cos(sA),y1=CY+R_OUT*Math.sin(sA);
  const x2=CX+R_OUT*Math.cos(eA),y2=CY+R_OUT*Math.sin(eA);
  const x3=CX+R_IN*Math.cos(eA), y3=CY+R_IN*Math.sin(eA);
  const x4=CX+R_IN*Math.cos(sA), y4=CY+R_IN*Math.sin(sA);
  const lg=sweep>Math.PI?1:0;
  const col=STATUS_COLOR_MAP[s.status]||'#8993A4';
  return `<path d="M${x1.toFixed(2)},${y1.toFixed(2)} A${R_OUT},${R_OUT} 0 ${lg},1 ${x2.toFixed(2)},${y2.toFixed(2)} L${x3.toFixed(2)},${y3.toFixed(2)} A${R_IN},${R_IN} 0 ${lg},0 ${x4.toFixed(2)},${y4.toFixed(2)} Z" fill="${col}"/>`;
}).join('');

const donutSvg = `<svg width="110" height="110" viewBox="0 0 128 128" xmlns="http://www.w3.org/2000/svg">
  ${donutPaths}
  <text x="64" y="58" text-anchor="middle" font-size="22" font-weight="700" fill="${TEXT1}" font-family="-apple-system,Arial,sans-serif">${metrics.totalIssues}</text>
  <text x="64" y="75" text-anchor="middle" font-size="10" fill="${TEXT2}" font-family="-apple-system,Arial,sans-serif">issues</text>
</svg>`;

const statusLegend = statusOverview.map(s => {
  const col = STATUS_COLOR_MAP[s.status]||'#8993A4';
  const pct = Math.round(s.count/totalIssues*100);
  return `<tr>
    <td style="padding:4px 8px 4px 0;width:12px;"><div style="width:8px;height:8px;border-radius:2px;background:${col};"></div></td>
    <td style="padding:4px 0;font-size:11px;color:${TEXT1};">${normalizeStatus(s.status)}</td>
    <td style="padding:4px 0;text-align:right;white-space:nowrap;">
      <span style="font-size:11px;font-weight:700;color:${TEXT1};">${s.count}</span>
      <span style="font-size:10px;color:${TEXT3};margin-left:2px;">(${pct}%)</span>
    </td>
  </tr>`;
}).join('');

// ── Derived values ────────────────────────────────────────────
const hasRisks   = kpis.blockedCount > 0 || kpis.overdueCount > 0;
const isComplete = sprintDaysLeft === 0;

// Health reason hint — tells manager WHY there's a risk
const healthReason = (() => {
  if (kpis.blockedCount > 0 && kpis.overdueCount > 0)
    return `${kpis.blockedCount} blocked · ${kpis.overdueCount} overdue`;
  if (kpis.blockedCount > 0)
    return `${kpis.blockedCount} issue${kpis.blockedCount>1?'s':''} blocked`;
  if (kpis.overdueCount > 0)
    return `${kpis.overdueCount} item${kpis.overdueCount>1?'s':''} overdue`;
  return kpis.healthGap > 0 ? `${kpis.healthGap}% behind target` : 'Ahead of schedule';
})();

// Executive summary — one sentence a manager can act on
const execSummary = (() => {
  const parts = [];
  parts.push(`Sprint is <strong>${isComplete ? 'complete' : sprintPct + '% elapsed'}</strong> with <strong>${kpis.completionRate}% of work delivered</strong> (${kpis.doneCount} of ${metrics.totalIssues} issues done).`);
  if (kpis.blockedCount > 0)
    parts.push(`<strong style="color:#BF2600;">${kpis.blockedCount} issue${kpis.blockedCount>1?'s are':' is'} blocked</strong> and require${kpis.blockedCount===1?'s':''} immediate attention.`);
  if (kpis.overdueCount > 0)
    parts.push(`<strong style="color:#BF2600;">${kpis.overdueCount} item${kpis.overdueCount>1?'s are':' is'} overdue</strong>.`);
  if (!hasRisks)
    parts.push('No blockers or overdue items. 🟢');
  return parts.join(' ');
})();

// ── 1. Alert banner (risks only) ─────────────────────────────
const alertBanner = hasRisks ? `
<tr><td style="background:#FFF3CD;border-left:4px solid #FF8B00;border-right:1px solid ${BORDER};padding:11px 20px;">
  <table width="100%" cellpadding="0" cellspacing="0"><tr valign="middle">
    <td style="font-size:10px;font-weight:700;color:#7A4F00;text-transform:uppercase;letter-spacing:0.07em;width:1%;white-space:nowrap;padding-right:12px;">⚠ Action Required</td>
    <td style="font-size:11px;color:#5C3D00;line-height:1.5;">
      ${(kpis.blockedList||[]).map(b=>`<strong>${b.key}</strong> blocked ${b.daysBlocked}d — ${b.assignee}`).join(' &nbsp;·&nbsp; ')}
      ${(kpis.overdueList||[]).length > 0 ? ' &nbsp;·&nbsp; ' + kpis.overdueList.map(o=>`<strong>${o.key}</strong> overdue ${o.daysOverdue}d`).join(', ') : ''}
    </td>
  </tr></table>
</td></tr>` : '';

// ── 2. Exec summary bar ───────────────────────────────────────
const execSummaryRow = `
<tr><td style="background:${SURFACE2};border-left:1px solid ${BORDER};border-right:1px solid ${BORDER};border-top:1px solid ${BORDER};padding:12px 24px;">
  <div style="font-size:12px;color:${TEXT1};line-height:1.7;">${execSummary}</div>
</td></tr>`;

// ── 3. Sprint Health + Timeline combined ──────────────────────
const healthAndTimeline = `
<tr><td style="background:${healthBg};border-left:1px solid ${BORDER};border-right:1px solid ${BORDER};border-top:4px solid ${healthBorder};padding:16px 30px;">
  <table width="100%" cellpadding="0" cellspacing="0"><tr valign="middle">

    <!-- Health status -->
    <td style="padding-right:20px;border-right:1px solid rgba(0,0,0,0.08);white-space:nowrap;">
      <div style="font-size:9px;font-weight:700;color:${healthColor};text-transform:uppercase;letter-spacing:0.08em;margin-bottom:4px;">Sprint Health</div>
      <div style="font-size:20px;font-weight:700;color:${healthColor};line-height:1;">${kpis.sprintHealth}</div>
      <div style="font-size:10px;color:${TEXT2};margin-top:4px;">${healthReason}</div>
    </td>

    <!-- Timeline bar -->
    <td style="padding-left:20px;">
      <table width="100%" cellpadding="0" cellspacing="0">
        <tr>
          <td style="padding-bottom:5px;font-size:9px;font-weight:700;letter-spacing:0.07em;color:${TEXT3};text-transform:uppercase;">Sprint Timeline</td>
          <td style="padding-bottom:5px;text-align:right;font-size:9px;font-weight:700;color:${daysColor};">${daysLabel}</td>
        </tr>
        <tr><td colspan="2">
          <table width="100%" cellpadding="0" cellspacing="0" style="background:#DFE1E6;border-radius:4px;height:8px;">
            <tr>
              <td width="${sprintBandFill}%" style="background:${barColor};height:8px;border-radius:4px;font-size:0;line-height:0;">&nbsp;</td>
              <td style="height:8px;font-size:0;line-height:0;">&nbsp;</td>
            </tr>
          </table>
        </td></tr>
        <tr>
          <td style="padding-top:4px;font-size:9px;color:${TEXT3};">${sprintStartFmt}</td>
          <td style="padding-top:4px;text-align:right;font-size:9px;color:${TEXT3};">${sprintEndFmt}</td>
        </tr>
      </table>
    </td>

  </tr></table>
</td></tr>`;

// ── 4. Unified metrics section — all numbers in one block ─────
// Row 1 (primary): Completion · Blocked · Due Soon — large, action-oriented
// Row 2 (secondary): Completed · Updated · Created · Avg Delivery — compact week context
const unifiedMetrics = `
<tr><td style="background:${SURFACE};border-left:1px solid ${BORDER};border-right:1px solid ${BORDER};border-top:1px solid ${BORDER};padding:18px 24px 14px;">

  <!-- Section label -->
  <div style="font-size:9px;font-weight:700;color:${TEXT3};text-transform:uppercase;letter-spacing:0.08em;margin-bottom:14px;">Sprint at a Glance</div>

  <!-- Row 1: 3 primary KPIs — large numbers, colour-coded by urgency -->
  <table width="100%" cellpadding="0" cellspacing="0" style="table-layout:fixed;margin-bottom:0;"><tr valign="top">

    <td style="padding-right:5px;">
      <table width="100%" cellpadding="0" cellspacing="0"><tr>
        <td style="border-left:3px solid #36B37E;background:#F2FBF6;border-radius:0 5px 5px 0;padding:11px 13px;">
          <div style="font-size:9px;font-weight:700;color:#006644;text-transform:uppercase;letter-spacing:0.08em;margin-bottom:4px;">Completion</div>
          <div style="font-size:26px;font-weight:700;color:#006644;line-height:1;">${kpis.completionRate}%</div>
          <div style="font-size:10px;color:${TEXT3};margin-top:4px;">${kpis.doneCount} of ${metrics.totalIssues} done</div>
        </td>
      </tr></table>
    </td>

    <td style="padding:0 5px;">
      <table width="100%" cellpadding="0" cellspacing="0"><tr>
        <td style="border-left:3px solid ${kpis.blockedCount>0?'#BF2600':BORDER};background:${kpis.blockedCount>0?'#FFEBE6':SURFACE2};border-radius:0 5px 5px 0;padding:11px 13px;">
          <div style="font-size:9px;font-weight:700;color:${kpis.blockedCount>0?'#BF2600':TEXT3};text-transform:uppercase;letter-spacing:0.08em;margin-bottom:4px;">Blocked</div>
          <div style="font-size:26px;font-weight:700;color:${kpis.blockedCount>0?'#BF2600':TEXT3};line-height:1;">${kpis.blockedCount}</div>
          <div style="font-size:10px;color:${TEXT3};margin-top:4px;">${kpis.blockedCount>0?'need attention':'no blockers 🟢'}</div>
        </td>
      </tr></table>
    </td>

    <td style="padding-left:5px;">
      <table width="100%" cellpadding="0" cellspacing="0"><tr>
        <td style="border-left:3px solid ${metrics.dueSoon>0?'#FF8B00':BORDER};background:${metrics.dueSoon>0?'#FFFAE6':SURFACE2};border-radius:0 5px 5px 0;padding:11px 13px;">
          <div style="font-size:9px;font-weight:700;color:${metrics.dueSoon>0?'#FF8B00':TEXT3};text-transform:uppercase;letter-spacing:0.08em;margin-bottom:4px;">Due Soon</div>
          <div style="font-size:26px;font-weight:700;color:${metrics.dueSoon>0?'#FF8B00':TEXT3};line-height:1;">${metrics.dueSoon}</div>
          <div style="font-size:10px;color:${TEXT3};margin-top:4px;">next 7 days</div>
        </td>
      </tr></table>
    </td>

  </tr></table>

  <!-- Divider with label -->
  <table width="100%" cellpadding="0" cellspacing="0" style="margin:12px 0 10px;">
    <tr valign="middle">
      <td style="border-top:1px solid ${BORDER};font-size:0;">&nbsp;</td>
      <td style="white-space:nowrap;padding:0 10px;font-size:9px;font-weight:700;color:${TEXT3};text-transform:uppercase;letter-spacing:0.07em;">This Week</td>
      <td style="border-top:1px solid ${BORDER};font-size:0;">&nbsp;</td>
    </tr>
  </table>

  <!-- Row 2: 4 weekly numbers — compact, equal columns -->
  <table width="100%" cellpadding="0" cellspacing="0" style="table-layout:fixed;"><tr valign="middle">

    <td style="text-align:center;padding:8px 4px;border-right:1px solid ${BORDER};">
      <div style="font-size:20px;font-weight:700;color:#006644;line-height:1;">${metrics.completed}</div>
      <div style="font-size:9px;font-weight:700;color:${TEXT3};text-transform:uppercase;letter-spacing:0.06em;margin-top:4px;">Completed</div>
    </td>

    <td style="text-align:center;padding:8px 4px;border-right:1px solid ${BORDER};">
      <div style="font-size:20px;font-weight:700;color:#0052CC;line-height:1;">${metrics.updated}</div>
      <div style="font-size:9px;font-weight:700;color:${TEXT3};text-transform:uppercase;letter-spacing:0.06em;margin-top:4px;">Updated</div>
    </td>

    <td style="text-align:center;padding:8px 4px;border-right:1px solid ${BORDER};">
      <div style="font-size:20px;font-weight:700;color:#6554C0;line-height:1;">${metrics.created}</div>
      <div style="font-size:9px;font-weight:700;color:${TEXT3};text-transform:uppercase;letter-spacing:0.06em;margin-top:4px;">Created</div>
    </td>

    <td style="text-align:center;padding:8px 4px;">
      <div style="font-size:20px;font-weight:700;color:#6554C0;line-height:1;">${kpis.avgLeadTime !== null ? kpis.avgLeadTime+'d' : '—'}</div>
      <div style="font-size:9px;font-weight:700;color:${TEXT3};text-transform:uppercase;letter-spacing:0.06em;margin-top:4px;">Avg Delivery</div>
    </td>

  </tr></table>

</td></tr>`;

// ── 5. Sprint Status donut ────────────────────────────────────
const donutSection = `
<tr><td style="background:${SURFACE};border-left:1px solid ${BORDER};border-right:1px solid ${BORDER};border-top:1px solid ${BORDER};padding:18px 30px;">
  <div style="font-size:11px;font-weight:700;color:${TEXT3};text-transform:uppercase;letter-spacing:0.07em;margin-bottom:14px;">Issue Breakdown</div>
  <table width="100%" cellpadding="0" cellspacing="0"><tr valign="middle">
    <td width="120" style="text-align:center;">${donutSvg}</td>
    <td style="padding-left:20px;"><table width="100%" cellpadding="0" cellspacing="0">${statusLegend}</table></td>
  </tr></table>
</td></tr>`;

// ── 6. Blocked detail (no duplication — replaces standalone card) ──
const blockedDetail = (kpis.blockedList||[]).length === 0 ? '' : `
<tr><td style="background:#FFEBE6;border-left:4px solid #BF2600;border-right:1px solid ${BORDER};border-top:1px solid ${BORDER};padding:16px 30px;">
  <div style="font-size:11px;font-weight:700;color:#BF2600;text-transform:uppercase;letter-spacing:0.07em;margin-bottom:12px;">
    Blocked Items — Immediate Attention Required
  </div>
  ${(kpis.blockedList||[]).slice(0,3).map(b=>`
  <table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:8px;"><tr valign="top">
    <td style="width:1%;white-space:nowrap;padding-right:10px;">
      <a href="${JIRA_BASE}/${b.key}" style="font-size:11px;font-weight:700;color:${BRAND_ACC};text-decoration:none;">${b.key}</a>
    </td>
    <td>
      <div style="font-size:12px;color:${TEXT1};font-weight:500;line-height:1.4;">${b.summary}</div>
      <div style="font-size:10px;color:${TEXT3};margin-top:2px;">
        ${b.assignee}${b.daysBlocked!==null?` · Blocked for <strong style="color:#BF2600;">${b.daysBlocked} days</strong>`:''}
        ${b.priority ? ` · ${b.priority}` : ''}
      </div>
    </td>
  </tr></table>`).join('')}
</td></tr>`;

// ── 7. PDF CTA — prominent ────────────────────────────────────
const ctaRow = `
<tr><td style="background:${BRAND};border-left:1px solid ${BORDER};border-right:1px solid ${BORDER};border-top:1px solid ${BORDER};padding:16px 30px;">
  <table width="100%" cellpadding="0" cellspacing="0"><tr valign="middle">
    <td>
      <div style="font-size:12px;font-weight:700;color:#FFFFFF;margin-bottom:3px;">📎 Full Report Attached</div>
      <div style="font-size:10px;color:rgba(255,255,255,0.55);">Includes activity log, theme progress, team breakdown &amp; delivery time analysis</div>
    </td>
    <td style="text-align:right;white-space:nowrap;padding-left:16px;">
