  'In Review':'#EAE6FF','En révision':'#EAE6FF','Revue en cours':'#EAE6FF',
  'To Do':'#F4F5F7','À faire':'#F4F5F7','Nouveau':'#F4F5F7','New':'#F4F5F7',
  'Blocked':'#FFEBE6'
