// ============================================================
// AGGREGATE REPORT METRICS
// Each item has _type set by its Label node upstream.
// We filter by _type — deterministic, accurate, rename-proof.
// ============================================================

const allItems = $input.all().map(i => i.json);

// ── Split by _type — exact, guaranteed ───────────────────────
const updatedIssues   = allItems.filter(i => i._type === 'updated');
const createdIssues   = allItems.filter(i => i._type === 'created');
const completedIssues = allItems.filter(i => i._type === 'completed');
const dueSoonIssues   = allItems.filter(i => i._type === 'dueSoon');
const allEpics        = allItems.filter(i => i._type === 'epics');
const allIssues       = allItems.filter(i => i._type === 'allIssues');
const configItem      = allItems.find(i => i._type === 'config') || {};

// ── Safe helpers ──────────────────────────────────────────────
const safeRound = (n, d = 1) => {
    if (!isFinite(n) || isNaN(n)) return 0;
    return Math.round(n * Math.pow(10, d)) / Math.pow(10, d);
};
const safePct = (num, den) => den > 0 ? Math.round((num / den) * 100) : 0;
const daysBetween = (isoA, isoB) => {
    if (!isoA || !isoB) return null;
    const diff = new Date(isoB).getTime() - new Date(isoA).getTime();
    return safeRound(diff / (1000 * 60 * 60 * 24), 1);
};

// ── Project identity ──────────────────────────────────────────
const _proj = allIssues[0]?.fields?.project || {};
const projectKey   = configItem.projectKey || _proj.key  || 'PROJECT';
const projectName  = _proj.name || projectKey;
const projectShort = projectName.replace(/^PFE Project:\s*/i, '').trim() || projectName;

// ── Sprint metadata ───────────────────────────────────────────
const _sprintArr    = allIssues[0]?.fields?.customfield_10020 || [];
const _activeSprint = _sprintArr.find(s => s.state === 'active') || _sprintArr[0] || {};

const sprintName  = _activeSprint.name || 'Current Sprint';
const sprintGoal  = _activeSprint.goal || '';

const fmtLong = (iso) => {
    if (!iso) return '—';
    return new Date(iso).toLocaleDateString('en-GB', {
        day: 'numeric', month: 'long', year: 'numeric'
    });
};

const sprintStart    = _activeSprint.startDate || null;
const sprintEnd      = _activeSprint.endDate   || null;
const sprintStartFmt = fmtLong(sprintStart);
const sprintEndFmt   = fmtLong(sprintEnd);
const sprintDates    = (sprintStart && sprintEnd)
    ? `${sprintStartFmt} — ${sprintEndFmt}` : (configItem.dateRange || '');

let sprintPct = 0, sprintDaysLeft = null;
if (sprintStart && sprintEnd) {
    const now   = Date.now();
    const start = new Date(sprintStart).getTime();
    const end   = new Date(sprintEnd).getTime();
    const total = end - start;
    sprintPct      = Math.min(100, Math.round((Math.max(0, now - start) / total) * 100));
    sprintDaysLeft = Math.max(0, Math.ceil((end - now) / (1000 * 60 * 60 * 24)));
}

// ── Classifiers (operate on allIssues — the status overview set) ──
const isDone       = i => i.fields?.status?.statusCategory?.key === 'done';
const isInProgress = i => i.fields?.status?.statusCategory?.key === 'indeterminate';
const isToDo       = i => i.fields?.status?.statusCategory?.key === 'new';
const isBlocked    = i => i.fields?.status?.name === 'BLOCKED';
const storyPts     = i => Number(i.fields?.customfield_10016) || 0;

const doneIssues    = allIssues.filter(isDone);
const inProgIssues  = allIssues.filter(isInProgress);
const toDoIssues    = allIssues.filter(isToDo);
const blockedIssues = allIssues.filter(isBlocked);
const totalCount    = allIssues.length || 1;

// ── Status Overview ───────────────────────────────────────────
// Normalize Jira status names (French → English) at source
const normalizeStatus = (s) => {
    if (!s) return 'Unknown';
    // Exact matches first
    const map = {
        'Done':          'Done',
        'Terminé':       'Done',
        'En cours':      'In Progress',
        'In Progress':   'In Progress',
        'En révision':   'In Review',
        'Revue en cours':'In Review',
        'In Review':     'In Review',
        'À faire':       'To Do',
        'Nouveau':       'To Do',
        'New':           'To Do',
        'To Do':         'To Do',
        'Blocked':       'Blocked',
    };
    if (map[s]) return map[s];
    // Fallback: pattern match for Jira variants like "Terminé(e)", "Terminée", etc.
    const sl = s.toLowerCase();
    if (sl.startsWith('terminé') || sl.startsWith('termine')) return 'Done';
    if (sl.startsWith('en cours')) return 'In Progress';
    if (sl.includes('révision') || sl.includes('review')) return 'In Review';
    if (sl.startsWith('à faire') || sl === 'nouveau' || sl === 'new') return 'To Do';
    return s;
};

const statusCount = {};
for (const issue of allIssues) {
    const s = normalizeStatus(issue.fields?.status?.name || 'Unknown');
    statusCount[s] = (statusCount[s] || 0) + 1;
}
const statusOverview = Object.entries(statusCount)
    .map(([status, count]) => ({ status, count }))
    .sort((a, b) => b.count - a.count);

// ── Priority Breakdown ────────────────────────────────────────
const priorityCount = {};
for (const issue of allIssues) {
    const p = issue.fields?.priority?.name || 'None';
    priorityCount[p] = (priorityCount[p] || 0) + 1;
}
const priorityBreakdown = Object.entries(priorityCount)
    .map(([priority, count]) => ({ priority, count }))
    .sort((a, b) => b.count - a.count);

// ── Epic Progress ─────────────────────────────────────────────
const epicProgress = allEpics.slice(0, 6).map(epic => {
    const epicKey  = epic.key;
    const epicName = epic.fields?.summary || epicKey;
    const children = allIssues.filter(i =>
        i.fields?.parent?.key === epicKey || i.fields?.customfield_10014 === epicKey
    );
    const done   = children.filter(isDone).length;
    const inProg = children.filter(isInProgress).length;
    const toDo   = children.filter(isToDo).length;
    const ct     = children.length || 1;
    return {
        key: epicKey, name: epicName,
        status: epic.fields?.status?.name,
        donePct:   Math.round((done   / ct) * 100),
        inProgPct: Math.round((inProg / ct) * 100),
        todoPct:   Math.round((toDo   / ct) * 100),
        total: children.length
    };
});

// ── Recent Activity (top 5 from updatedIssues — already sorted by Jira) ──
const recentActivity = updatedIssues.slice(0, 5).map(i => ({
    key:      i.key,
    summary:  i.fields?.summary?.substring(0, 80),
    status:   normalizeStatus(i.fields?.status?.name || 'Unknown'),
    priority: i.fields?.priority?.name || 'None',
    assignee: i.fields?.assignee?.displayName || 'Unassigned',
    updated:  i.fields?.updated?.substring(0, 10),
    type:     i.fields?.issuetype?.name
}));

// ── Team Workload ─────────────────────────────────────────────
const assigneeCount = {};
for (const issue of allIssues) {
    const a = issue.fields?.assignee?.displayName || 'Unassigned';
    assigneeCount[a] = (assigneeCount[a] || 0) + 1;
}
const teamWorkload = Object.entries(assigneeCount)
    .map(([assignee, count]) => ({ assignee, count, pct: safePct(count, totalCount) }))
    .sort((a, b) => b.count - a.count);

// ── KPI: Velocity & Story Points ─────────────────────────────
const spVelocity      = doneIssues.reduce((s, i) => s + storyPts(i), 0);
const spTotal         = allIssues.reduce((s, i) => s + storyPts(i), 0);
const spRemaining     = inProgIssues.concat(toDoIssues).reduce((s, i) => s + storyPts(i), 0);
const spCompletedWeek = completedIssues.reduce((s, i) => s + storyPts(i), 0);

// ── KPI: Completion Rate ──────────────────────────────────────
const completionRate = safePct(doneIssues.length, totalCount);

// ── KPI: Sprint Health ────────────────────────────────────────
const healthGap    = sprintPct - completionRate;
const sprintHealth = healthGap <= 0  ? 'On Track'
    : healthGap <= 20 ? 'Slight Risk'
    : healthGap <= 40 ? 'At Risk'
    : 'Critical';
const sprintHealthScore = Math.max(0, Math.min(100, Math.round(100 - healthGap * 1.5)));

// ── KPI: Lead Time ────────────────────────────────────────────
const leadTimes = doneIssues
    .map(i => daysBetween(i.fields?.created, i.fields?.resolutiondate))
    .filter(d => d !== null && d >= 0);
const avgLeadTime = leadTimes.length > 0
    ? safeRound(leadTimes.reduce((s, d) => s + d, 0) / leadTimes.length, 1) : null;
const minLeadTime = leadTimes.length > 0 ? Math.min(...leadTimes) : null;
const maxLeadTime = leadTimes.length > 0 ? Math.max(...leadTimes) : null;

// ── KPI: Lead Time by Priority ────────────────────────────────
const ltByPriority = {};
for (const issue of doneIssues) {
    const p  = issue.fields?.priority?.name || 'None';
    const lt = daysBetween(issue.fields?.created, issue.fields?.resolutiondate);
    if (lt !== null && lt >= 0) {
        if (!ltByPriority[p]) ltByPriority[p] = [];
        ltByPriority[p].push(lt);
    }
}
const leadTimeByPriority = Object.entries(ltByPriority).map(([priority, times]) => ({
    priority,
    avgDays: safeRound(times.reduce((s, t) => s + t, 0) / times.length, 1),
    count:   times.length
})).sort((a, b) => {
    const order = ['Highest', 'High', 'Medium', 'Low', 'Lowest'];
    return order.indexOf(a.priority) - order.indexOf(b.priority);
});

// ── KPI: Blocked Issues ───────────────────────────────────────
const blockedList = blockedIssues.map(i => ({
    key:      i.key,
    summary:  i.fields?.summary?.substring(0, 70),
    assignee: i.fields?.assignee?.displayName || 'Unassigned',
    priority: i.fields?.priority?.name || 'None',
    daysBlocked: (() => {
        const changed = i.fields?.statuscategorychangedate;
        if (!changed) return null;
        return Math.floor((Date.now() - new Date(changed).getTime()) / (1000 * 60 * 60 * 24));
    })()
}));

// ── KPI: Overdue Issues ───────────────────────────────────────
const today = new Date(); today.setHours(0, 0, 0, 0);
const overdueList = allIssues
    .filter(i => {
        if (isDone(i)) return false;
        const due = i.fields?.duedate;
        if (!due) return false;
        return new Date(due) < today;
    })
    .map(i => ({
        key:         i.key,
        summary:     i.fields?.summary?.substring(0, 70),
        duedate:     i.fields?.duedate,
        assignee:    i.fields?.assignee?.displayName || 'Unassigned',
        priority:    i.fields?.priority?.name || 'None',
        status:      normalizeStatus(i.fields?.status?.name || 'Unknown'),
        daysOverdue: Math.floor(
            (today.getTime() - new Date(i.fields.duedate).getTime()) / (1000 * 60 * 60 * 24)
        )
    }))
    .sort((a, b) => b.daysOverdue - a.daysOverdue);

// ── KPI: Per-Assignee Breakdown ───────────────────────────────
// Pre-compute SP done this week per assignee from completedIssues
const spWeekByAssignee = {};
for (const issue of completedIssues) {
    const a = issue.fields?.assignee?.displayName || 'Unassigned';
    spWeekByAssignee[a] = (spWeekByAssignee[a] || 0) + storyPts(issue);
}

const assigneeMap = {};
for (const issue of allIssues) {
    const a = issue.fields?.assignee?.displayName || 'Unassigned';
    if (!assigneeMap[a]) assigneeMap[a] = {
        done: 0, inProgress: 0, toDo: 0, blocked: 0,
        sp: 0, spDone: 0, leadTimes: []
    };
    const m = assigneeMap[a];
    if (isDone(issue))          { m.done++;       m.spDone += storyPts(issue); }
    else if (isInProgress(issue)) m.inProgress++;
    else if (isToDo(issue))       m.toDo++;
    if (isBlocked(issue))         m.blocked++;
    m.sp += storyPts(issue);
    const lt = daysBetween(issue.fields?.created, issue.fields?.resolutiondate);
    if (lt !== null && lt >= 0 && isDone(issue)) m.leadTimes.push(lt);
}
const assigneeKPIs = Object.entries(assigneeMap).map(([assignee, m]) => {
    const assigneeTotal = m.done + m.inProgress + m.toDo;
    return {
        assignee,
        total:          assigneeTotal,
        done:           m.done,
        inProgress:     m.inProgress,
        toDo:           m.toDo,
        blocked:        m.blocked,
        completionRate: safePct(m.done, assigneeTotal || 1),
        storyPoints:    m.sp,
        spDone:         m.spDone,
        spDoneWeek:     spWeekByAssignee[assignee] || 0,
        avgLeadTime:    m.leadTimes.length > 0
            ? safeRound(m.leadTimes.reduce((s, t) => s + t, 0) / m.leadTimes.length, 1)
            : null,
        pct: safePct(assigneeTotal, totalCount)
    };
}).sort((a, b) => b.total - a.total);

// ── KPI: Type Breakdown ───────────────────────────────────────
const typeMap = {};
for (const issue of allIssues) {
    const t = issue.fields?.issuetype?.name || 'Unknown';
    if (!typeMap[t]) typeMap[t] = { total: 0, done: 0, sp: 0 };
    typeMap[t].total++;
    if (isDone(issue)) typeMap[t].done++;
    typeMap[t].sp += storyPts(issue);
}
const typeBreakdown = Object.entries(typeMap)
    .map(([type, m]) => ({
        type, total: m.total, done: m.done,
        donePct: safePct(m.done, m.total),
        sp: m.sp, pct: safePct(m.total, totalCount)
    }))
    .sort((a, b) => b.total - a.total);

// ── Assemble ──────────────────────────────────────────────────
const kpis = {
    storyPointsCompleted: spVelocity,
    storyPointsTotal:     spTotal,
    storyPointsRemaining: spRemaining,
    storyPointsWeek:      spCompletedWeek,
    completionRate,
    throughputWeek:       completedIssues.length,
    throughputSprint:     doneIssues.length,
    sprintHealth, sprintHealthScore, healthGap,
    avgLeadTime, minLeadTime, maxLeadTime,
    leadTimeByPriority,
    doneCount:       doneIssues.length,
    inProgressCount: inProgIssues.length,
    toDoCount:       toDoIssues.length,
    blockedCount:    blockedIssues.length,
    overdueCount:    overdueList.length,
    blockedList, overdueList, assigneeKPIs, typeBreakdown
};

return [{
    json: {
        projectKey,
        emailTo:      configItem.emailTo      || '',

        weekStart:    configItem.weekStart     || '',
        weekEnd:      configItem.weekEnd       || '',
        projectName, projectShort,
        sprintName, sprintGoal, sprintDates,
        sprintStartFmt, sprintEndFmt,
        sprintPct, sprintDaysLeft,
        reportTitle: `${sprintName} — Weekly Report — ${projectShort}`,
        weekLabel:   configItem.weekLabel || '',
        today:       configItem.today     || '',
        dateRange:   configItem.dateRange || sprintDates,
        metrics: {
            completed:   completedIssues.length,
            updated:     updatedIssues.length,
            created:     createdIssues.length,
            dueSoon:     dueSoonIssues.length,
            totalIssues: allIssues.length
        },
        kpis,
        statusOverview, priorityBreakdown,
        teamWorkload, epicProgress, recentActivity,
        dueSoonIssues: dueSoonIssues.slice(0, 5).map(i => ({
            key:      i.key,
            summary:  i.fields?.summary?.substring(0, 70),
            duedate:  i.fields?.duedate,
            assignee: i.fields?.assignee?.displayName || 'Unassigned',
            priority: i.fields?.priority?.name
        }))
    }
}];
